import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

export default function LoginPage() {
  const [phone, setPhone] = useState('');
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  useEffect(() => {
    // If already verified, show profile view instead of redirecting
  }, []);

  const handleSubmit = e => {
    e.preventDefault();
    if (!phone.trim()) return;
    localStorage.setItem('pizzaAuth', JSON.stringify({ phone: phone.trim(), verified: false }));
    navigate('/verify');
  };

  const handleLogout = () => {
    localStorage.removeItem('pizzaAuth');
    window.location.reload();
  };

  // Profile view for logged-in users
  if (auth.verified) {
    return (
      <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">
        {/* Navy Header */}
        <div
          className="px-5 pt-10 pb-12 text-center"
          style={{ background: 'linear-gradient(160deg, #006491 0%, #004d6e 100%)' }}
        >
          <div className="w-20 h-20 rounded-full bg-white/20 flex items-center justify-center text-4xl mx-auto mb-3">
            👤
          </div>
          <h1 className="text-white font-black text-2xl">{auth.name || 'שלום!'}</h1>
          <p className="text-blue-200 text-sm mt-1" dir="ltr">{auth.phone}</p>
        </div>

        <div className="px-4 -mt-5 space-y-3">
          {/* Profile Card */}
          <div className="bg-white rounded-2xl shadow-md p-5 space-y-4">
            <div className="flex items-center gap-3 py-1 border-b border-gray-50 pb-3">
              <span className="text-2xl">📱</span>
              <div>
                <p className="text-xs text-gray-400 font-medium">מספר טלפון</p>
                <p className="font-bold text-gray-800" dir="ltr">{auth.phone}</p>
              </div>
              <span className="mr-auto text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold">
                ✓ מאומת
              </span>
            </div>

            <button
              onClick={() => navigate('/history')}
              className="w-full flex items-center gap-3 py-2 text-right"
            >
              <span className="text-2xl">📋</span>
              <div className="flex-1">
                <p className="font-bold text-gray-800">ההזמנות שלי</p>
                <p className="text-xs text-gray-400">היסטוריה ותוכנית נאמנות</p>
              </div>
              <span className="text-gray-300">←</span>
            </button>

            <button
              onClick={() => navigate('/tracker')}
              className="w-full flex items-center gap-3 py-2 text-right border-t border-gray-50 pt-3"
            >
              <span className="text-2xl">📍</span>
              <div className="flex-1">
                <p className="font-bold text-gray-800">מעקב הזמנה</p>
                <p className="text-xs text-gray-400">עקוב אחרי ההזמנה הפעילה</p>
              </div>
              <span className="text-gray-300">←</span>
            </button>
          </div>

          <button
            onClick={handleLogout}
            className="w-full py-4 rounded-2xl border-2 border-red-100 text-tomato font-bold bg-white hover:bg-red-50 transition active:scale-95"
          >
            🚪 התנתק
          </button>
        </div>
      </div>
    );
  }

  // Login view for unauthenticated users
  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">
      {/* Big Navy Hero */}
      <div
        className="px-5 pt-14 pb-16 text-center"
        style={{ background: 'linear-gradient(160deg, #006491 0%, #004d6e 100%)' }}
      >
        <div className="text-7xl mb-4">🍕</div>
        <h1 className="text-white font-black text-3xl mb-1">פיצה סטורי</h1>
        <p className="text-blue-200 text-sm">הכנסו לחשבון כדי להזמין ולעקוב</p>
      </div>

      {/* Login Card — overlapping the hero */}
      <div className="px-4 -mt-6">
        <div className="bg-white rounded-2xl shadow-xl p-6">
          <h2 className="font-black text-gray-900 text-xl mb-1">כניסה לחשבון</h2>
          <p className="text-gray-400 text-sm mb-5">הכנס מספר טלפון לקבלת קוד אימות</p>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">מספר טלפון</label>
              <input
                type="tel"
                value={phone}
                onChange={e => setPhone(e.target.value)}
                required
                placeholder="050-0000000"
                className="w-full border-2 border-gray-100 rounded-xl px-4 py-4 text-xl text-center focus:border-tomato focus:outline-none transition bg-gray-50"
                dir="ltr"
                autoFocus
              />
            </div>
            <button
              type="submit"
              className="w-full bg-tomato text-white py-4 rounded-2xl font-black text-lg shadow-md hover:bg-red-700 transition active:scale-95"
            >
              שלח קוד אימות 📲
            </button>
          </form>

          <button
            onClick={() => navigate('/')}
            className="mt-3 w-full border-2 border-gray-100 text-gray-500 py-3.5 rounded-2xl font-bold hover:bg-gray-50 transition text-sm"
          >
            ← חזרה לתפריט
          </button>
        </div>

        {/* Benefits */}
        <div className="mt-4 bg-navy/5 rounded-2xl p-4 space-y-2.5">
          {[
            { icon: '📋', text: 'עקוב אחרי ההזמנות שלך בזמן אמת' },
            { icon: '🏆', text: 'צבור נקודות לפיצה חינם' },
            { icon: '⚡', text: 'קבלת כתובת אוטומטית בהזמנה הבאה' },
          ].map((b, i) => (
            <div key={i} className="flex items-center gap-3 text-sm text-gray-600">
              <span className="text-lg">{b.icon}</span>
              <span>{b.text}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
